#include <SPI.h>
extern uint16_t rle_encode_block(uint8_t*,uint16_t,uint8_t*,uint16_t);
#define FLASH_CS 10
#define RAW_SZ 252
#define PAGE_SZ 256
uint8_t raw[RAW_SZ],rle_out[PAGE_SZ];
uint16_t raw_i=0;
uint32_t flash_page=0;
void flash_setup(){
  SPI.begin();
  pinMode(FLASH_CS,OUTPUT);
  digitalWrite(FLASH_CS,HIGH);}
void flash_write_enable(){
  digitalWrite(FLASH_CS,LOW);SPI.transfer(0x06);digitalWrite(FLASH_CS,HIGH);}
void flash_write_page(uint32_t pg,uint8_t* d,uint16_t n){
  flash_write_enable();
  uint32_t addr=pg*PAGE_SZ;
  SPI.beginTransaction(SPISettings(8000000,MSBFIRST,SPI_MODE0));
  digitalWrite(FLASH_CS,LOW);
  SPI.transfer(0x02);
  SPI.transfer((addr>>16)&0xFF);
  SPI.transfer((addr>>8)&0xFF);
  SPI.transfer(addr&0xFF);
  for(uint16_t i=0;i<n;i++)SPI.transfer(d[i]);
  digitalWrite(FLASH_CS,HIGH);
  SPI.endTransaction();
  delay(3);}
uint32_t crc32_block(uint8_t* d,uint16_t n){
  uint32_t c=0xFFFFFFFF;
  for(uint16_t i=0;i<n;i++){c^=d[i];for(int j=0;j<8;j++)c=(c&1)?(c>>1)^0xEDB88320:(c>>1);}
  return ~c;}
void sample_4ch(){
  if(raw_i+4>RAW_SZ)return;
  for(int i=0;i<4;i++)raw[raw_i++]=(uint8_t)(analogRead(A0+i)>>2);}
void flush_block(){
  uint16_t rlen=rle_encode_block(raw,raw_i,rle_out,PAGE_SZ-4);
  uint32_t crc=crc32_block(rle_out,rlen);
  rle_out[rlen++]=(crc>>24)&0xFF;
  rle_out[rlen++]=(crc>>16)&0xFF;
  rle_out[rlen++]=(crc>>8)&0xFF;
  rle_out[rlen++]=crc&0xFF;
  flash_write_page(flash_page++,rle_out,rlen);
  Serial.print("ratio:");
  Serial.println((float)raw_i/rlen,2);
  raw_i=0;}
void fault_check(){
  if(flash_page>=32768){
    Serial.println("FAULT:FLASH_FULL");while(1);}}
unsigned long pt=0;
void setup(){Serial.begin(115200);flash_setup();}
void loop(){
  unsigned long n=millis();
  if(n-pt>=10){pt=n;sample_4ch();}
  if(raw_i>=RAW_SZ){fault_check();flush_block();}}
